oxy_webhelp_navlinks = {"aws_evaluate_options_cloud_acc_setup-d26997e12171":{"topics":[{"title":"AWS cloud discovery","shortdesc":"<p class=\"shortdesc\">The cloud discovery feature provides a read-only view of AWS resources in <span class=\"ph\">RSC<\/span>. This feature separates workload discovery from workload protection, so         you can view all the resources that exist before choosing what to protect.<\/p>","href":"saas\/aws_cloud_discovery.html","attributes":{"data-id":"aws_cloud_discovery"},"menu":{"hasChildren":false},"tocID":"aws_cloud_discovery-d26997e12188","topics":[]},{"title":"Manual versus CFT configuration for AWS cloud account","shortdesc":"<p class=\"shortdesc\">A comparative overview of the manual and CloudFormation Template methods for adding         an AWS cloud account to <span class=\"ph\">RSC<\/span>.<\/p>","href":"saas\/aws_manual_vs_cft_config_cld_acc.html","attributes":{"data-id":"aws_manual_vs_cft_config_cld_acc"},"menu":{"hasChildren":false},"tocID":"aws_manual_vs_cft_config_cld_acc-d26997e12202","topics":[]},{"title":"Multiple versus individual AWS cloud account addition","shortdesc":"<p class=\"shortdesc\">A comparative overview of multiple and individual addition of AWS cloud         accounts.<\/p>","href":"saas\/aws_multiple_vs_indv_acc_addition.html","attributes":{"data-id":"aws_multiple_vs_indv_acc_addition"},"menu":{"hasChildren":false},"tocID":"aws_multiple_vs_indv_acc_addition-d26997e12216","topics":[]},{"title":"Data scanning in AWS","shortdesc":"<p class=\"shortdesc\">When you enable data scanning in an AWS account, <span class=\"ph\">RSC<\/span> scans and         classifies your AWS data based on their sensitivity and generate intelligent insights. Data         scanning helps you manage cloud posture risks.<\/p>","href":"saas\/data_protection_insights_aws.html","attributes":{"data-id":"data_protection_insights_aws"},"menu":{"hasChildren":false},"tocID":"data_protection_insights_aws-d26997e12227","topics":[]},{"title":"AWS role chaining","shortdesc":"<p class=\"shortdesc\">With the AWS role chaining feature, <span class=\"ph\">RSC<\/span> introduces a dedicated AWS         account that serves as a centralized gateway to securely manage multiple AWS accounts from a         single administrative point.<\/p>","href":"saas\/aws_role_chaining.html","attributes":{"data-id":"aws_role_chaining"},"menu":{"hasChildren":false},"tocID":"aws_role_chaining-d26997e12241","topics":[]}]}};